const SESSION_ID = 'YOUR_SESSION_ID';

const body = $input.first().json.body || $input.first().json;
const event = body.data ? body.data.object : body;

const customerName = event.customer_details
  ? event.customer_details.name || 'Customer'
  : 'Customer';

const phone = event.customer_details && event.customer_details.phone
  ? event.customer_details.phone.replace(/[^0-9]/g, '')
  : '';

const email = event.customer_details
  ? event.customer_details.email || ''
  : '';

const amount = event.amount_total
  ? (event.amount_total / 100).toFixed(2)
  : '0.00';

const currency = (event.currency || 'usd').toUpperCase();
const paymentId = event.payment_intent || event.id || '';

if (!phone || phone.length < 7) {
  return [{ json: { skip: true, reason: 'No phone number on payment', email, paymentId } }];
}

const message = `Hi ${customerName}! Your payment of ${currency} ${amount} has been received. Payment ID: ${paymentId.slice(-8)}. Thank you for your purchase! If you have any questions, just reply to this message.`;

return [{
  json: {
    session_id: SESSION_ID,
    chat_id: phone + '@c.us',
    message: message,
    customer_name: customerName,
    amount: amount,
    currency: currency,
    phone: phone,
    skip: false
  }
}];

const data = $('Format Receipt').first().json;
return [{ json: {
  status: 'sent',
  customer: data.customer_name,
  amount: data.currency + ' ' + data.amount
} }];
